import { chromium } from '/Users/prynq/Desktop/kartar/sachmeetsb.github.io/node_modules/playwright-core/index.mjs';

const DIR = '/Users/prynq/Desktop/kartar/sachmeetsb.github.io/plans/design/styleframes';
const routes = ['route-A', 'route-B', 'route-C'];

const browser = await chromium.launch();
const ctx = await browser.newContext({ viewport: { width: 1440, height: 900 }, deviceScaleFactor: 2 });

for (const r of routes) {
  const page = await ctx.newPage();
  const errors = [];
  page.on('pageerror', e => errors.push(String(e)));
  await page.goto(`file://${DIR}/${r}.html`, { waitUntil: 'networkidle' }).catch(async () => {
    await page.goto(`file://${DIR}/${r}.html`, { waitUntil: 'load' });
  });
  await page.waitForTimeout(2500);
  await page.screenshot({ path: `${DIR}/${r}.png` });
  await page.screenshot({ path: `${DIR}/${r}-full.png`, fullPage: true });
  console.log(`${r}: shot ok${errors.length ? ' | pageerrors: ' + errors.join(' ; ') : ''}`);
  await page.close();
}
await browser.close();
console.log('done');

